const OLD_ITEM_ID_ALIASES = {"0cygJX1IKCzvWw1b":"x2VIpCSzghynU8c5","lNGUlpxPqCSrMkit":"dhbmaVvqxPoAB4q0","dns2gvnKvE0HDxhn":"2Gqvi42QCTSCG7tO","GDpJwJUShXKuEBvY":"oZJX2XJgw23kDXPc","S3TAv0k5a281qMqG":"27KJalb5VBosRB8B","JFuavNs0sG8ikClw":"oclSElwvY8MjXuIv","zlTJ8whZtCY2abor":"NSAiD9LVesJTicxy","O49Op2BxTVJzBrSj":"O8tcA1MvPpSgET9R","IBupLj0xLa4eKncN":"vByBBvvQ2lPbrxjE"};

function extractCraftItemOldId(uuid) {
  const raw = String(uuid ?? "").trim();
  if (!raw) return "";
  const itemMatch = raw.match(/(?:^|\.)(Item\.([A-Za-z0-9]+))$/);
  if (itemMatch) return itemMatch[2];
  return raw.replace(/^Item\./, "");
}
